const input = $input.first().json;

const messageType = input.message_type || 'text';
const hasFile = Boolean(input.file_id);

const supportedMessageTypes = ['photo', 'document'];

const shouldAnalyze =
  hasFile &&
  supportedMessageTypes.includes(messageType);

return [
  {
    json: {
      ...input,
      should_analyze_file: shouldAnalyze
    }
  }
];

const input = $input.first().json;

return [
  {
    json: {
      ...input,
      file_analysis_status: 'not_needed',
      file_analysis_text: null,
      file_analysis_json: null
    }
  }
];

const original = $('Decide file analysis').first().json;
const getFile = $('Telegram getFile').first().json;

const item = $input.first();
const binaryMeta = item.binary?.data;

if (!binaryMeta) {
  return [
    {
      json: {
        ...original,
        file_analysis_status: 'failed',
        file_analysis_text: 'File was received, but binary metadata was not available for AI analysis.',
        file_analysis_json: {
          summary: null,
          detected_type: original.message_type || null,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0,
          error: 'No binary.data metadata found'
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

// IMPORTANT:
// In n8n binary mode, binary.data.data may contain "filesystem-v2..." instead of real base64.
// So we must read the real binary buffer and convert it to base64 ourselves.
let fileBase64;

try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  fileBase64 = buffer.toString('base64');
} catch (error) {
  return [
    {
      json: {
        ...original,
        file_analysis_status: 'failed',
        file_analysis_text: 'File was received, but n8n could not read the binary buffer for AI analysis.',
        file_analysis_json: {
          summary: null,
          detected_type: original.message_type || null,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0,
          error: error.message
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

const messageType = original.message_type || 'document';

function detectMimeType(messageType, original, binaryMeta, getFile) {
  const fileName = String(
    original.file_name ||
    binaryMeta?.fileName ||
    getFile?.result?.file_path ||
    ''
  ).toLowerCase();

  const telegramPath = String(getFile?.result?.file_path || '').toLowerCase();

  // Telegram photos often come without correct MIME type.
  // If message_type is photo, force image MIME.
  if (messageType === 'photo') {
    if (fileName.endsWith('.png') || telegramPath.endsWith('.png')) {
      return 'image/png';
    }

    if (fileName.endsWith('.webp') || telegramPath.endsWith('.webp')) {
      return 'image/webp';
    }

    return 'image/jpeg';
  }

  const originalMime = original.mime_type || '';
  const binaryMime = binaryMeta?.mimeType || '';

  // Ignore generic MIME type if we can detect a better one from extension.
  const candidateMime =
    originalMime && originalMime !== 'application/octet-stream'
      ? originalMime
      : binaryMime && binaryMime !== 'application/octet-stream'
        ? binaryMime
        : '';

  if (candidateMime) {
    return candidateMime;
  }

  if (fileName.endsWith('.pdf') || telegramPath.endsWith('.pdf')) {
    return 'application/pdf';
  }

  if (fileName.endsWith('.jpg') || fileName.endsWith('.jpeg') || telegramPath.endsWith('.jpg') || telegramPath.endsWith('.jpeg')) {
    return 'image/jpeg';
  }

  if (fileName.endsWith('.png') || telegramPath.endsWith('.png')) {
    return 'image/png';
  }

  if (fileName.endsWith('.webp') || telegramPath.endsWith('.webp')) {
    return 'image/webp';
  }

  if (fileName.endsWith('.txt')) {
    return 'text/plain';
  }

  if (fileName.endsWith('.csv')) {
    return 'text/csv';
  }

  if (fileName.endsWith('.json')) {
    return 'application/json';
  }

  return 'application/octet-stream';
}

const mimeType = detectMimeType(messageType, original, binaryMeta, getFile);

const fileName =
  original.file_name ||
  binaryMeta.fileName ||
  getFile?.result?.file_path ||
  'telegram_file';

const caption = original.caption || '';
const content = original.content || original.message || '';

const supportedMimeTypes = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/heic',
  'image/heif',
  'application/pdf',
  'text/plain',
  'text/csv',
  'application/json',
  'text/markdown',
  'text/html',
  'application/xml',
  'text/xml'
];

const isSupported =
  messageType === 'photo' ||
  supportedMimeTypes.includes(mimeType);

if (!isSupported) {
  return [
    {
      json: {
        ...original,
        file_name: fileName,
        mime_type: mimeType,
        telegram_file_path: getFile?.result?.file_path || null,
        file_analysis_status: 'unsupported',
        file_analysis_text:
          `File received but not deeply analyzed. ` +
          `Unsupported MIME type for direct Gemini analysis: ${mimeType}. ` +
          `File name: ${fileName}. ` +
          (caption ? `Caption: ${caption}.` : ''),
        file_analysis_json: {
          summary: null,
          detected_type: messageType,
          language: null,
          visible_or_extracted_text: null,
          keywords: [],
          important_details: [],
          suggested_topics: [],
          confidence: 0.2,
          error: `Unsupported MIME type: ${mimeType}`
        },
        skip_gemini_analysis: true
      }
    }
  ];
}

const prompt = `
You analyze a Telegram user file for a personal memory and notes bot called Memoraq.

Return only valid JSON.
Do not use markdown.
Do not wrap the response in code fences.

Analyze the file and extract useful information for later search, topic classification, and memory retrieval.

Telegram metadata:
- Message type: ${messageType}
- File name: ${fileName}
- MIME type: ${mimeType}
- Caption: ${caption || '[no caption]'}
- Existing text/content: ${content || '[no text]'}

For photos:
- Describe what is visible.
- Do not identify real people by name.
- If it looks like a receipt, document, product, place, screenshot, certificate, food, travel photo, or work-related image, say so.
- Extract visible text if possible.

For PDFs and text documents:
- Summarize the main content.
- Extract organizations, dates, amounts, document type, and important keywords if present.
- If it looks like a CV/resume, invoice, agreement, bank/tax document, report, sales file, legal document, medical document, or travel document, classify it.

Return exactly this JSON structure:
{
  "summary": "Short useful summary in English, 1-3 sentences",
  "detected_type": "photo | receipt | invoice | contract | resume | report | legal_document | tax_document | bank_document | travel_document | screenshot | product | place | text_document | pdf_document | other",
  "language": "detected language or null",
  "visible_or_extracted_text": "important visible/extracted text or null",
  "keywords": ["keyword1", "keyword2", "keyword3"],
  "important_details": [
    {
      "label": "date | amount | company | person | location | document_number | other",
      "value": "detail value"
    }
  ],
  "suggested_topics": ["Topic 1", "Topic 2"],
  "confidence": 0.85
}
`.trim();

const requestBody = {
  contents: [
    {
      parts: [
        {
          text: prompt
        },
        {
          inline_data: {
            mime_type: mimeType,
            data: fileBase64
          }
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json'
  }
};

return [
  {
    json: {
      ...original,
      file_name: fileName,
      mime_type: mimeType,
      telegram_file_path: getFile?.result?.file_path || null,
      gemini_request_body: requestBody,
      skip_gemini_analysis: false
    }
  }
];

const input = $input.first().json;

const clean = { ...input };

delete clean.gemini_request_body;
delete clean.skip_gemini_analysis;

return [
  {
    json: clean
  }
];

const original = $('Prepare Gemini file request').first().json;
const response = $input.first().json;

let raw = '';

try {
  raw =
    response.candidates?.[0]?.content?.parts
      ?.map(part => part.text || '')
      .join('\n')
      .trim() || '';
} catch (e) {
  raw = '';
}

raw = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    summary: raw || 'The file was analyzed, but the response could not be parsed as JSON.',
    detected_type: original.message_type || 'other',
    language: null,
    visible_or_extracted_text: null,
    keywords: [],
    important_details: [],
    suggested_topics: [],
    confidence: 0.3,
    parse_error: e.message
  };
}

const keywords = Array.isArray(parsed.keywords)
  ? parsed.keywords.filter(Boolean).slice(0, 12)
  : [];

const importantDetails = Array.isArray(parsed.important_details)
  ? parsed.important_details.slice(0, 12)
  : [];

const suggestedTopics = Array.isArray(parsed.suggested_topics)
  ? parsed.suggested_topics.filter(Boolean).slice(0, 5)
  : [];

const summary = parsed.summary || '';
const detectedType = parsed.detected_type || original.message_type || 'other';
const language = parsed.language || null;
const extractedText = parsed.visible_or_extracted_text || null;
const confidence = Number(parsed.confidence || 0);

const detailsText = importantDetails
  .map(d => {
    if (!d) return null;
    const label = d.label || 'detail';
    const value = d.value || '';
    return value ? `${label}: ${value}` : null;
  })
  .filter(Boolean)
  .join('; ');

const fileAnalysisText = [
  `AI file analysis:`,
  summary ? `Summary: ${summary}` : null,
  detectedType ? `Detected type: ${detectedType}` : null,
  language ? `Language: ${language}` : null,
  extractedText ? `Extracted/visible text: ${String(extractedText).slice(0, 1500)}` : null,
  keywords.length ? `Keywords: ${keywords.join(', ')}` : null,
  detailsText ? `Important details: ${detailsText}` : null,
  suggestedTopics.length ? `Suggested topics from file: ${suggestedTopics.join(', ')}` : null,
  `Confidence: ${confidence}`
]
  .filter(Boolean)
  .join('\n');

const clean = {
  ...original,

  file_analysis_status: 'done',
  file_analysis_text: fileAnalysisText,
  file_analysis_json: {
    summary,
    detected_type: detectedType,
    language,
    visible_or_extracted_text: extractedText,
    keywords,
    important_details: importantDetails,
    suggested_topics: suggestedTopics,
    confidence
  }
};

delete clean.gemini_request_body;
delete clean.skip_gemini_analysis;

return [
  {
    json: clean
  }
];
